async function loadCommentsForCard(boardPubkey: string, cardDTag: string): Promise<CardComment[]> {
        const aTagValue = `30302:${boardPubkey}:${cardDTag}`;
        const filter: NDKFilter = {
            kinds: [30303 as NDKKind],
            '#a': [aTagValue]
        };
        const events = await ndk.fetchEvents(filter);
        const comments: CardComment[] = [];
        for (const event of events) {
            const eTag = event.tags.find(t => t[0] === 'e');
            const parentId = eTag ? eTag[1] : null;
            const parentType = eTag ? (eTag[2] === 'reply' ? 'reply' : 'card') : 'card';
            comments.push({
                id: event.id,
                pubkey: event.pubkey,
                content: event.content,
                created_at: event.created_at!,
                parentId,
                parentType
            });
        }
        comments.sort((a, b) => a.created_at - b.created_at);
        return comments;
    }

    async function publishComment(
        boardPubkey: string,
        cardDTag: string,
        cardEventId: string,
        content: string,
        parentCommentEventId?: string,
        parentCommentAuthorPubkey?: string
    ): Promise<void> {
        const commentEvent = new NDKEvent(ndk);
        commentEvent.kind = 30303 as NDKKind;
        commentEvent.content = content;
        commentEvent.tags = [
            ['a', `30302:${boardPubkey}:${cardDTag}`]
        ];
        if (parentCommentEventId) {
            commentEvent.tags.push(['e', parentCommentEventId, 'reply']);
            if (parentCommentAuthorPubkey) {
                commentEvent.tags.push(['p', parentCommentAuthorPubkey]);
            }
        } else {
            commentEvent.tags.push(['e', cardEventId, 'card']);
        }
        await ndkInstance.publishEvent(commentEvent);
    }

